import { v } from "convex/values";
import { query, mutation } from "./_generated/server";

export const list = query({
  args: {
    sessionId: v.optional(v.id("sessions")),
  },
  handler: async (ctx, args) => {
    if (args.sessionId) {
      // Get session-specific reminders and global reminders
      const sessionReminders = await ctx.db
        .query("reminders")
        .withIndex("by_session", (q) => q.eq("sessionId", args.sessionId))
        .collect();

      const globalReminders = await ctx.db
        .query("reminders")
        .withIndex("by_session", (q) => q.eq("sessionId", undefined))
        .collect();

      return [...globalReminders, ...sessionReminders].sort(
        (a, b) => b.priority - a.priority
      );
    }

    return await ctx.db.query("reminders").collect();
  },
});

export const getActive = query({
  args: {
    sessionId: v.optional(v.id("sessions")),
  },
  handler: async (ctx, args) => {
    const allReminders = await ctx.db
      .query("reminders")
      .withIndex("by_active", (q) => q.eq("active", true))
      .collect();

    // Filter to session-specific + global reminders
    return allReminders
      .filter((r) => r.sessionId === args.sessionId || r.sessionId === undefined)
      .sort((a, b) => b.priority - a.priority);
  },
});

export const create = mutation({
  args: {
    sessionId: v.optional(v.id("sessions")),
    content: v.string(),
    persistent: v.boolean(),
    priority: v.optional(v.number()),
    triggerCondition: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    return await ctx.db.insert("reminders", {
      sessionId: args.sessionId,
      content: args.content,
      persistent: args.persistent,
      active: true,
      priority: args.priority ?? 0,
      triggerCondition: args.triggerCondition,
    });
  },
});

export const update = mutation({
  args: {
    id: v.id("reminders"),
    content: v.optional(v.string()),
    persistent: v.optional(v.boolean()),
    active: v.optional(v.boolean()),
    priority: v.optional(v.number()),
    triggerCondition: v.optional(v.string()),
  },
  handler: async (ctx, args) => {
    const { id, ...updates } = args;
    const filteredUpdates = Object.fromEntries(
      Object.entries(updates).filter(([_, v]) => v !== undefined)
    );
    await ctx.db.patch(id, filteredUpdates);
  },
});

export const toggle = mutation({
  args: {
    id: v.id("reminders"),
    active: v.boolean(),
  },
  handler: async (ctx, args) => {
    await ctx.db.patch(args.id, { active: args.active });
  },
});

export const remove = mutation({
  args: { id: v.id("reminders") },
  handler: async (ctx, args) => {
    await ctx.db.delete(args.id);
  },
});

export const deactivateNonPersistent = mutation({
  args: {
    sessionId: v.optional(v.id("sessions")),
  },
  handler: async (ctx, args) => {
    const reminders = await ctx.db
      .query("reminders")
      .withIndex("by_active", (q) => q.eq("active", true))
      .collect();

    for (const reminder of reminders) {
      if (
        !reminder.persistent &&
        (reminder.sessionId === args.sessionId || reminder.sessionId === undefined)
      ) {
        await ctx.db.patch(reminder._id, { active: false });
      }
    }
  },
});

